-- Mythogen AME Schema - SurrealDB
-- Field of Trust + Affinity Mapping + Convergence Engine

-- Enable relaxed typing for prototyping
DEFINE TABLE schema VERSION 1;

-- ═══════════════════════════════════════════════════════════
-- CORE ENTITIES
-- ═══════════════════════════════════════════════════════════

DEFINE TABLE person SCHEMAFULL;
DEFINE FIELD name ON person TYPE string;
DEFINE FIELD createdAt ON person TYPE int;
DEFINE FIELD fotState ON person FLEXIBLETYPE;
DEFINE FIELD weakStates ON person FLEXIBLETYPE;
DEFINE FIELD vCrystal ON person FLEXIBLETYPE;
DEFINE FIELD socialRadius ON person TYPE string DEFAULT 'global';

DEFINE TABLE affinity SCHEMAFULL;
DEFINE FIELD topicId ON affinity TYPE string;
DEFINE FIELD targetId ON affinity TYPE string;
DEFINE FIELD witnessId ON affinity TYPE string;
DEFINE FIELD strength ON affinity TYPE float;
DEFINE FIELD polarity ON affinity TYPE string DEFAULT 'neutral';
DEFINE FIELD createdAt ON affinity TYPE int;
DEFINE FIELD lastUpdated ON affinity TYPE int;
DEFINE FIELD witnessCount ON affinity TYPE int DEFAULT 1;

DEFINE TABLE topic SCHEMAFULL;
DEFINE FIELD name ON topic TYPE string;
DEFINE FIELD category ON topic TYPE string DEFAULT 'collective';
DEFINE FIELD affinityStrength ON topic TYPE float DEFAULT 0;
DEFINE FIELD participantIds ON topic FLEXIBLETYPE;
DEFINE FIELD emergenceScore ON topic TYPE float DEFAULT 0;
DEFINE FIELD createdAt ON topic TYPE int;
DEFINE FIELD lastActivity ON topic TYPE int;

DEFINE TABLE fot_indicator SCHEMAFULL;
DEFINE FIELD name ON fot_indicator TYPE string;
DEFINE FIELD value ON fot_indicator TYPE float;
DEFINE FIELD trajectory ON fot_indicator TYPE string DEFAULT 'stable';
DEFINE FIELD lastSensed ON fot_indicator TYPE int;

DEFINE TABLE resonance_event SCHEMAFULL;
DEFINE FIELD personId ON resonance_event TYPE string;
DEFINE FIELD topicId ON resonance_event TYPE string;
DEFINE FIELD witnessId ON resonance_event TYPE string;
DEFINE FIELD type ON resonance_event TYPE string;
-- type: 'witnessed' | 'expressed' | 'received' | 'reflected'
DEFINE FIELD createdAt ON resonance_event TYPE int;

DEFINE TABLE v_crystal SCHEMAFULL;
DEFINE FIELD personId ON v_crystal TYPE string;
DEFINE FIELD coreValue ON v_crystal TYPE string;
DEFINE FIELD expressionExamples ON v_crystal FLEXIBLETYPE;
DEFINE FIELD crystallizationDate ON v_crystal TYPE int;
DEFINE FIELD stabilityScore ON v_crystal TYPE float;
DEFINE FIELD practicingOthers ON v_crystal FLEXIBLETYPE;
DEFINE FIELD witnessCount ON v_crystal TYPE int DEFAULT 0;

DEFINE TABLE convergence_point SCHEMAFULL;
DEFINE FIELD personId ON convergence_point TYPE string;
DEFINE FIELD weakIndicators ON convergence_point FLEXIBLETYPE;
DEFINE FIELD emergentTopicId ON convergence_point TYPE string;
DEFINE FIELD overlapScore ON convergence_point TYPE float;
DEFINE FIELD urgency ON convergence_point TYPE string DEFAULT 'medium';
DEFINE FIELD suggestedActions ON convergence_point FLEXIBLETYPE;
DEFINE FIELD createdAt ON convergence_point TYPE int;
DEFINE FIELD expiresAt ON convergence_point TYPE int;

-- ═══════════════════════════════════════════════════════════
-- INDEXES FOR PERFORMANCE
-- ═══════════════════════════════════════════════════════════

DEFINE INDEX idx_person_social ON person FIELDS socialRadius;
DEFINE INDEX idx_affinity_target ON affinity FIELDS targetId;
DEFINE INDEX idx_affinity_topic ON affinity FIELDS topicId;
DEFINE INDEX idx_topic_emergence ON topic FIELDS emergenceScore;
DEFINE INDEX idx_convergence_expires ON convergence_point FIELDS expiresAt;
DEFINE INDEX idx_convergence_overlap ON convergence_point FIELDS overlapScore;
DEFINE INDEX idx_resonance_person ON resonance_event FIELDS personId;
DEFINE INDEX idx_resonance_topic ON resonance_event FIELDS topicId;

-- ═══════════════════════════════════════════════════════════
-- FUNCTIONS
-- ═══════════════════════════════════════════════════════════

-- Hologram Principle: FOT composite = MIN of all indicators, not average
DEFINE FUNCTION fn_fot_composite($indicators array) RETURN float (
    RETURN array::min($indicators)
);

-- Emergent affinity calculation
DEFINE FUNCTION fn_calc_affinity($personId string, $topicId string) RETURN float (
    LET $signals = [
        (SELECT count() FROM resonance_event WHERE personId = $personId AND topicId = $topicId) * 0.3,
        (SELECT count() FROM affinity WHERE targetId = $personId AND topicId = $topicId) * 0.25,
        (SELECT count() FROM resonance_event WHERE topicId = $topicId) * 0.2
    ];
    RETURN Math::min(1, array::sum($signals))
);

-- Convergence detection
DEFINE FUNCTION fn_find_convergences() RETURN array (
    LET $weak = SELECT personId, weakStates FROM person;
    LET $topics = SELECT * FROM topic WHERE emergenceScore > 0.5 ORDER BY emergenceScore DESC;
    RETURN $weak MAP {
        personId: .personId,
        weakIndicators: .weakStates,
        convergences: $topics FILTER fn_calc_overlap(.weakStates, .id) > 0.7
    }
);

DEFINE FUNCTION fn_calc_overlap($weak array, $topicId string) RETURN float (
    -- Simplified: check topic tags against weak indicators
    LET $topic = SELECT * FROM topic WHERE id = $topicId;
    LET $match = array::len(array::intersect($weak, $topic[0].tags));
    RETURN $match / array::len($weak)
);

-- ═══════════════════════════════════════════════════════════
-- EMBEDDINGS (for semantic search)
-- ═══════════════════════════════════════════════════════════

DEFINE TABLE embedding SCHEMAFULL;
DEFINE FIELD entityType ON embedding TYPE string; -- person | topic | affinity
DEFINE FIELD entityId ON embedding TYPE string;
DEFINE FIELD vector ON embedding TYPE array<float>;
DEFINE FIELD model ON embedding TYPE string;
DEFINE FIELD createdAt ON embedding TYPE int;

DEFINE INDEX idx_embedding_vector ON embedding FIELDS vector ANN {
    distance: cosine,
    capacity: 10000,
    m: 16,
    ef_construction: 200
};

-- ═══════════════════════════════════════════════════════════
-- TIMELOCK SYSTEM (from existing Mythogen)
-- ═══════════════════════════════════════════════════════════

DEFINE TABLE timelock SCHEMAFULL;
DEFINE FIELD entityType ON timelock TYPE string;
DEFINE FIELD entityId ON timelock TYPE string;
DEFINE FIELD unlockAt ON timelock TYPE int;
DEFINE FIELD reason ON timelock TYPE string;
DEFINE FIELD createdBy ON timelock TYPE string;

-- ═══════════════════════════════════════════════════════════
-- Y-CARDS & SACRED CLOWN (from existing Mythogen)
-- ═══════════════════════════════════════════════════════════

DEFINE TABLE y_card SCHEMAFULL;
DEFINE FIELD fromId ON y_card TYPE string;
DEFINE FIELD toId ON y_card TYPE string;
DEFINE FIELD question ON y_card TYPE string;
DEFINE FIELD response ON y_card FLEXIBLETYPE;
DEFINE FIELD createdAt ON y_card TYPE int;
DEFINE FIELD respondedAt ON y_card FLEXIBLETYPE;

DEFINE TABLE sacred_clown SCHEMAFULL;
DEFINE FIELD triggerType ON sacred_clown TYPE string;
-- triggerType: 'over_alignment' | 'stagnation' | 'rigidity'
DEFINE FIELD activationThreshold ON sacred_clown TYPE float;
DEFINE FIELD intervention ON sacred_clown FLEXIBLETYPE;

// Mythogen AME API - Axum (Rust)
// Field of Trust + Affinity Mapping + Convergence Engine

use axum::{
    routing::{get, post, ws},
    Router, Json, extract::{Path, Query, State, WebSocketUpgrade},
    http::StatusCode,
};
use serde::{Deserialize, Serialize};
use surrealdb::engine::local::Db;
use std::sync::Arc;

// ═══════════════════════════════════════════════════════════
// CORE TYPES (matching schema)
-- ═══════════════════════════════════════════════════════════

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct Person {
    pub id: Option<String>,
    pub name: String,
    pub created_at: i64,
    pub fot_state: Option<FOTState>,
    pub weak_states: Vec<String>,
    pub v_crystal: Option<VCrystal>,
    pub social_radius: String,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct FOTState {
    pub indicators: Vec<FOTIndicator>,
    pub composite: f64, // hologram: min of all, not average
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct FOTIndicator {
    pub name: String, // "Psychological Safety", "Trust", etc.
    pub value: f64,
    pub trajectory: String, // "strengthening" | "weakening" | "stable"
    pub last_sensed: i64,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct VCrystal {
    pub id: Option<String>,
    pub core_value: String,
    pub expression_examples: Vec<String>,
    pub crystallization_date: i64,
    pub stability_score: f64,
    pub practicing_others: Vec<String>,
    pub witness_count: i32,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct Affinity {
    pub id: Option<String>,
    pub topic_id: String,
    pub target_id: String,
    pub witness_id: String,
    pub strength: f64,
    pub polarity: String,
    pub created_at: i64,
    pub last_updated: i64,
    pub witness_count: i32,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct Topic {
    pub id: Option<String>,
    pub name: String,
    pub category: String,
    pub affinity_strength: f64,
    pub participant_ids: Vec<String>,
    pub emergence_score: f64,
    pub created_at: i64,
    pub last_activity: i64,
    pub tags: Vec<String>, // For convergence matching
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct ResonanceEvent {
    pub id: Option<String>,
    pub person_id: String,
    pub topic_id: String,
    pub witness_id: String,
    #[serde(rename = "type")]
    pub event_type: String,
    pub created_at: i64,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct ConvergencePoint {
    pub id: Option<String>,
    pub person_id: String,
    pub weak_indicators: Vec<String>,
    pub emergent_topic_id: String,
    pub overlap_score: f64,
    pub urgency: String,
    pub suggested_actions: Vec<String>,
    pub created_at: i64,
    pub expires_at: i64,
}

// ═══════════════════════════════════════════════════════════
// REQUEST/RESPONSE TYPES
-- ═══════════════════════════════════════════════════════════

#[derive(Debug, Deserialize)]
pub struct WitnessAffinityRequest {
    pub witness_id: String,
    pub target_id: String,
    pub topic_id: String,
    pub strength: f64,
}

#[derive(Debug, Deserialize)]
pub struct SenseFOTRequest {
    pub person_id: String,
    pub indicators: Vec<FOTIndicator>,
}

#[derive(Debug, Deserialize)]
pub struct CrystallizeValueRequest {
    pub person_id: String,
    pub core_value: String,
    pub expression_examples: Vec<String>,
}

#[derive(Debug, Deserialize)]
pub struct ConvergenceQuery {
    pub min_overlap: Option<f64>,
    pub limit: Option<usize>,
}

#[derive(Debug, Serialize)]
pub struct FieldCompositeResponse {
    pub composite: f64, // Hologram: minimum of all indicators
    pub indicators: Vec<FOTIndicator>,
    pub weakest_link: String, // Which indicator is dragging down the field
}

// ═══════════════════════════════════════════════════════════
// APP STATE
-- ═══════════════════════════════════════════════════════════

pub struct AppState {
    pub db: Arc<Surreal<Db>>,
}

// ═══════════════════════════════════════════════════════════
// HANDLERS
-- ═══════════════════════════════════════════════════════════

// --- Field of Trust ---

async fn get_person_field(
    State(state): State<AppState>,
    Path(person_id): Path<String>,
) -> Result<Json<FOTState>, StatusCode> {
    let person: Option<Person> = state.db
        .select(("person", &person_id))
        .await
        .map_err(|_| StatusCode::NOT_FOUND)?;

    person.and_then(|p| p.fot_state)
        .map(Json)
        .ok_or(StatusCode::NOT_FOUND)
}

async fn get_field_composite(
    State(state): State<AppState>,
) -> Result<Json<FieldCompositeResponse>, StatusCode> {
    // Get all people, aggregate FOT indicators
    let people: Vec<Person> = state.db
        .select("person")
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    // Aggregate indicators across community (simplified)
    let all_indicators: Vec<FOTIndicator> = people
        .iter()
        .filter_map(|p| p.fot_state.as_ref())
        .flat_map(|fs| fs.indicators.clone())
        .collect();

    // Hologram principle: composite = MIN, not average
    let composite = all_indicators.iter()
        .map(|i| i.value)
        .fold(f64::INFINITY, f64::min);

    let weakest = all_indicators.iter()
        .min_by(|a, b| a.value.partial_cmp(&b.value).unwrap())
        .map(|i| i.name.clone())
        .unwrap_or_default();

    Ok(Json(FieldCompositeResponse {
        composite,
        indicators: all_indicators,
        weakest_link: weakest,
    }))
}

async fn sense_indicators(
    State(state): State<AppState>,
    Json(req): Json<SenseFOTRequest>,
) -> Result<Json<FOTIndicator>, StatusCode> {
    // AI-assisted FOT indicator sensing
    // In production: call LLM to analyze behavioral signals

    let indicator = FOTIndicator {
        name: req.indicators.first().unwrap().name.clone(),
        value: req.indicators.first().unwrap().value,
        trajectory: "stable".to_string(),
        last_sensed: chrono::Utc::now().timestamp(),
    };

    // Update person record
    let _: Option<Person> = state.db
        .update(("person", &req.person_id))
        .merge(serde_json::json!({
            "fot_state": {
                "indicators": [indicator],
                "composite": indicator.value // simplified
            }
        }))
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok(Json(indicator))
}

// --- Affinities ---

async fn witness_affinity(
    State(state): State<AppState>,
    Json(req): Json<WitnessAffinityRequest>,
) -> Result<Json<Affinity>, StatusCode> {
    let affinity = Affinity {
        id: None,
        topic_id: req.topic_id,
        target_id: req.target_id,
        witness_id: req.witness_id,
        strength: req.strength,
        polarity: "neutral".to_string(),
        created_at: chrono::Utc::now().timestamp(),
        last_updated: chrono::Utc::now().timestamp(),
        witness_count: 1,
    };

    let created: Option<Affinity> = state.db
        .create("affinity")
        .content(affinity)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    created.map(Json).ok_or(StatusCode::INTERNAL_SERVER_ERROR)
}

async fn get_person_affinities(
    State(state): State<AppState>,
    Path(person_id): Path<String>,
) -> Result<Json<Vec<Affinity>>, StatusCode> {
    let affinities: Vec<Affinity> = state.db
        .query("SELECT * FROM affinity WHERE target_id = $id ORDER BY strength DESC")
        .bind(("id", person_id))
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .take(0)
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok(Json(affinities))
}

// --- Convergence ---

async fn find_convergences(
    State(state): State<AppState>,
    Query(query): Query<ConvergenceQuery>,
) -> Result<Json<Vec<ConvergencePoint>>, StatusCode> {
    let min_overlap = query.min_overlap.unwrap_or(0.7);
    let limit = query.limit.unwrap_or(10);

    // Get weak states + emergent topics, find overlaps
    let convergences: Vec<ConvergencePoint> = state.db
        .query("SELECT * FROM convergence_point WHERE overlap_score >= $min ORDER BY overlap_score DESC LIMIT $lim")
        .bind(("min", min_overlap))
        .bind(("lim", limit))
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .take(0)
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok(Json(convergences))
}

async fn create_convergence(
    State(state): State<AppState>,
    Json(req): Json<ConvergencePoint>,
) -> Result<Json<ConvergencePoint>, StatusCode> {
    let created: Option<ConvergencePoint> = state.db
        .create("convergence_point")
        .content(req)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    created.map(Json).ok_or(StatusCode::INTERNAL_SERVER_ERROR)
}

// --- Topics ---

async fn get_topics_emergence(
    State(state): State<AppState>,
) -> Result<Json<Vec<Topic>>, StatusCode> {
    let topics: Vec<Topic> = state.db
        .query("SELECT * FROM topic ORDER BY emergence_score DESC")
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .take(0)
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok(Json(topics))
}

// --- Values (V-Crystal) ---

async fn crystallize_value(
    State(state): State<AppState>,
    Json(req): Json<CrystallizeValueRequest>,
) -> Result<Json<VCrystal>, StatusCode> {
    let crystal = VCrystal {
        id: None,
        core_value: req.core_value,
        expression_examples: req.expression_examples,
        crystallization_date: chrono::Utc::now().timestamp(),
        stability_score: 0.5, // Starts at 0.5, grows with witness count
        practicing_others: vec![],
        witness_count: 0,
    };

    let created: Option<VCrystal> = state.db
        .create("v_crystal")
        .content(crystal.clone())
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    // Update person record
    let _: Option<Person> = state.db
        .update(("person", &req.person_id))
        .merge(serde_json::json!({ "v_crystal": crystal }))
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    created.map(Json).ok_or(StatusCode::INTERNAL_SERVER_ERROR)
}

// ═══════════════════════════════════════════════════════════
// ROUTES
-- ═══════════════════════════════════════════════════════════

pub fn router(state: AppState) -> Router {
    Router::new()
        // FOT
        .route("/api/people/{id}/field", get(get_person_field))
        .route("/api/field/composite", get(get_field_composite))
        .route("/api/field/sense", post(sense_indicators))

        // Affinities
        .route("/api/affinities/witness", post(witness_affinity))
        .route("/api/people/{id}/affinities", get(get_person_affinities))

        // Convergence
        .route("/api/convergence", get(find_convergences))
        .route("/api/convergence", post(create_convergence))

        // Topics
        .route("/api/topics/emergence", get(get_topics_emergence))

        // Values
        .route("/api/values/crystallize", post(crystallize_value))

        // WebSocket for real-time field updates
        .route("/api/ws/field", get(ws_handler))
        .with_state(state)
}

async fn ws_handler(
    ws: WebSocketUpgrade,
    State(state): State<AppState>,
) -> Response {
    ws.on_upgrade(|socket| async move {
        // Handle real-time field updates
        // Subscribe to SurrealDB changes or publish manually
        let _ = socket.send(Message::Text(Json(serde_json::json!({
            "type": "subscribed",
            "channel": "field"
        })).to_string())).await;
    })
}

fn main() {
    // Initialize SurrealDB
    let rt = tokio::runtime::Runtime::new().unwrap();
    let db = rt.block_on(async {
        Surreal::new::<Db>(("mem",)).await.unwrap()
    });
    db.use_ns("mythogen").use_db("ame").await.unwrap();

    let state = AppState { db: Arc::new(db) };
    let app = router(state);

    axum::Server::bind(&"0.0.0.0:3000".parse().unwrap())
        .serve(app.into_make_service())
        .await
        .unwrap();
}

// Sacred Geometry Integration for Mythogen AME
// Tetragrammaton (TTGM) + Toroidal Field Dynamics

// ═══════════════════════════════════════════════════════════
// TETRAGRAMMATON - 4 Core Vectors (TTGM)
// ═══════════════════════════════════════════════════════════

// The 4 fundamental directions of the field
// These map to FOT indicators but with explicit TTGM geometry
enum TTGMVector {
    YOD  = "source"      // The point of origin - consciousness/initiation
    HE   = "reception"   // Receiving, feminine principle - receptivity
    VAV  = "flow"        // Connecting, masculine principle - action/flow
    HE   = "return"      // Completion, returning to source - integration
}

const TTGM_LABELS = {
    YOD: { name: "Source", color: "#FF6B35", direction: "initiation" },
    HE:  { name: "Recept", color: "#4ECDC4", direction: "receiving" },
    VAV: { name: "Flow",   color: "#FFE66D", direction: "action" },
    HE:  { name: "Return",color: "#95E1D3", direction: "integration" }
};

// Map FOT indicators to TTGM vectors (5 indicators across 4 vectors)
const INDICATOR_TO_TTGM = {
    "Psychological Safety": "YOD",   // Source - safe to begin
    "Trust":                "HE",    // Recept - open to receive
    "Coherence":            "VAV",   // Flow - aligned action
    "Attunement":           "HE",    // Recept (secondary)
    "Openness":            "VAV",   // Flow (secondary)
    // 5th indicator maps to Return for toroidal completion
    "Integration":          "HE+",   // Return - the completing arc
};

// ═══════════════════════════════════════════════════════════
// TOROIDAL FIELD CALCULATIONS
// ═══════════════════════════════════════════════════════════

interface TTGMField {
    yod: number;   // Source strength (0-1)
    he_recept: number;  // Recept strength
    vav: number;    // Flow strength
    he_return: number;  // Return/completion strength

    // Derived
    toroidalCoherence: number;  // How complete the torus is
    fluxDirection: "inward" | "outward" | "stable";
    sacredRatio: number;        // YOD:VAV:HE balance (should be ~1:1:1)
}

function computeTTGM(indicators: FOTIndicator[]): TTGMField {
    // Aggregate indicators into TTGM vectors
    const vectors = {
        yod: 0, he_recept: 0, vav: 0, he_return: 0
    };

    const counts = { yod: 0, he_recept: 0, vav: 0, he_return: 0 };

    for (const ind of indicators) {
        const vector = INDICATOR_TO_TTGM[ind.name];
        if (vector) {
            vectors[vector] += ind.value;
            counts[vector]++;
        }
    }

    // Average each vector
    for (const key of Object.keys(counts) as Array<keyof typeof counts>) {
        if (counts[key] > 0) {
            vectors[key] /= counts[key];
        }
    }

    // Toroidal coherence = how close to perfect the torus is
    // Not average - minimum (hologram) but weighted by vector balance
    const toroidalCoherence = Math.min(
        vectors.yod, 
        vectors.he_recept, 
        vectors.vav, 
        vectors.he_return
    ) * sacredRatioScore(vectors);

    // Flux direction - is energy flowing in, out, or balanced?
    const inflow = vectors.yod + vectors.he_recept;
    const outflow = vectors.vav + vectors.he_return;
    const fluxDirection = inflow > outflow * 1.2 ? "inward" :
                          outflow > inflow * 1.2 ? "outward" : "stable";

    return {
        ...vectors,
        toroidalCoherence,
        fluxDirection,
        sacredRatio: sacredRatioScore(vectors)
    };
}

function sacredRatioScore(vectors: TTGMField): number {
    // Sacred ratio: vectors should be roughly equal (1:1:1:1)
    // Deviation reduces coherence - sacred geometry isn't about max, it's about balance
    const values = [vectors.yod, vectors.he_recept, vectors.vav, vectors.he_return];
    const mean = values.reduce((a, b) => a + b, 0) / 4;
    const variance = values.reduce((sum, v) => sum + Math.pow(v - mean, 2), 0) / 4;
    const stdDev = Math.sqrt(variance);

    // Score: 1 - normalized deviation (closer to 1 = more sacred balance)
    return Math.max(0, 1 - (stdDev / mean));
}

// ═══════════════════════════════════════════════════════════
// FRACTAL SCALING - Community Field Within Person Field
// ═══════════════════════════════════════════════════════════

interface FractalLayer {
    scale: "atom" | "person" | "community" | "planet" | "star" | "universe";
    ttgm: TTGMField;
    parentField?: string; // ID of the containing field
    childFields: string[]; // IDs of fields this contains
    resonanceFrequency: number; // Oscillation rate (Hz)
}

function computeFractalResonance(
    layer: FractalLayer,
    parentTTGM: TTGMField | null
): number {
    if (!parentTTGM) return 1.0;

    // Child field resonates with parent - coherence multiplicative
    // If parent toroidalCoherence = 0.7 and child = 0.8, combined = 0.56
    return layer.ttgm.toroidalCoherence * parentTTGM.toroidalCoherence;
}

// ═══════════════════════════════════════════════════════════
// TTGM VISUALIZATION (for the Lens interface)
// ═══════════════════════════════════════════════════════════

const TTGM_VISUALIZATION = {
    // 4 vectors as a cross/tetragrammaton
    // Rotated 90° gives us the basic shape:
    //
    //         YOD (top)
    //           ↑
    //   HE←─────┼────→VAV
    //    (left)      (right)
    //           ↓
    //        HE+ (bottom/return)
    //
    // In 3D: this wraps into a torus

    render: (field: TTGMField) => {
